def make_sound(thing):
    return thing.speak()

class Dog:
    def speak(self): return "Woof!"

class Robot:
    def speak(self): return "BEEP BOOP"

class Baby:
    def speak(self): return "Waaaa!"

for thing in [Dog(), Robot(), Baby()]:
    print(make_sound(thing))
